  1	import {
  2	  Button,
  3	  MenuToggle,
  4	  MenuToggleElement,
  5	  Select,
  6	  SelectGroup,
  7	  SelectList,
  8	  SelectOption,
  9	  SelectOptionProps,
 10	  TextInputGroup,
 11	  TextInputGroupMain,
 12	  TextInputGroupUtilities,
 13	} from '@patternfly/react-core';
 14	import { TimesIcon } from '@patternfly/react-icons';
 15	import React from 'react';
 16	import { useTranslation } from 'react-i18next';
 17	import { getBrowserTimezone, getTimezoneOffset } from '../date-utils';
 18	import { TestIds } from '../test-ids';
 19	
 20	// Extend Intl type to include supportedValuesOf (available in modern browsers)
 21	declare global {
 22	  // eslint-disable-next-line @typescript-eslint/no-namespace
 23	  namespace Intl {
 24	    function supportedValuesOf(key: string): string[];
 25	  }
 26	}
 27	
 28	// Format timezone for display: "America/New_York (UTC-05:00)"
 29	const formatTimezoneLabel = (timezone: string): string => {
 30	  const { label } = getTimezoneOffset(timezone);
 31	  return label ? `${timezone} (${label})` : timezone;
 32	};
 33	
 34	// Curated list of common timezones
 35	const DEFAULT_TIMEZONES = [
 36	  'UTC',
 37	  getBrowserTimezone(), // Browser's local timezone
 38	  'America/New_York',
 39	  'America/Chicago',
 40	  'America/Denver',
 41	  'America/Los_Angeles',
 42	  'Europe/London',
 43	  'Europe/Paris',
 44	  'Europe/Berlin',
 45	  'Asia/Tokyo',
 46	  'Asia/Shanghai',
 47	  'Asia/Kolkata',
 48	  'Australia/Sydney',
 49	  // Remove duplicates if browser TZ is in the list
 50	].filter((tz, index, arr) => arr.indexOf(tz) === index);
 51	
 52	const getAllTimezones = (): string[] => {
 53	  try {
 54	    return Intl.supportedValuesOf('timeZone');
 55	  } catch {
 56	    // Fallback for older browsers
 57	    return DEFAULT_TIMEZONES;
 58	  }
 59	};
 60	
 61	interface TimezoneDropdownProps {
 62	  value?: string;
 63	  onChange?: (timezone: string) => void;
 64	  isDisabled?: boolean;
 65	}
 66	
 67	export const TimezoneDropdown: React.FC<TimezoneDropdownProps> = ({
 68	  onChange,
 69	  value = '',
 70	  isDisabled,
 71	}) => {
 72	  const { t } = useTranslation('plugin__logging-view-plugin');
 73	  const [isOpen, setIsOpen] = React.useState(false);
 74	  const localTimezone = React.useMemo(() => getBrowserTimezone(), []);
 75	  const [selected, setSelected] = React.useState<string>(value || localTimezone);
 76	  const [inputValue, setInputValue] = React.useState<string>(value || localTimezone);
 77	  const [filterValue, setFilterValue] = React.useState<string>('');
 78	  const [focusedItemIndex, setFocusedItemIndex] = React.useState<number | null>(null);
 79	  const [activeItemId, setActiveItemId] = React.useState<string | null>(null);
 80	  const textInputRef = React.useRef<HTMLInputElement>();
 81	
 82	  const initialSelectOptions: SelectOptionProps[] = React.useMemo(() => {
 83	    return getAllTimezones().map((tz) => ({
 84	      value: tz,
 85	      children: formatTimezoneLabel(tz),
 86	    }));
 87	  }, []);
 88	
 89	  const commonTimezoneOptions: SelectOptionProps[] = React.useMemo(() => {
 90	    return DEFAULT_TIMEZONES.map((tz) => ({
 91	      value: tz,
 92	      children: formatTimezoneLabel(tz),
 93	    }));
 94	  }, []);
 95	
 96	  const [selectOptions, setSelectOptions] =
 97	    React.useState<SelectOptionProps[]>(initialSelectOptions);
 98	
 99	  const NO_RESULTS = 'no results';
100	
101	  React.useEffect(() => {
102	    const timezone = value || localTimezone;
103	    setSelected(timezone);
104	    setInputValue(formatTimezoneLabel(timezone));
105	  }, [value]);
106	
107	  React.useEffect(() => {
108	    let newSelectOptions: SelectOptionProps[] = initialSelectOptions;
109	
110	    // Filter menu items based on the text input value when one exists
111	    if (filterValue) {
112	      newSelectOptions = initialSelectOptions.filter((menuItem) =>
113	        String(menuItem.children).toLowerCase().includes(filterValue.toLowerCase()),
114	      );
115	
116	      // When no options are found after filtering, display 'No results found'
117	      if (!newSelectOptions.length) {
118	        newSelectOptions = [
119	          {
120	            isAriaDisabled: true,
121	            children: `${t('No results found for')} "${filterValue}"`,
122	            value: NO_RESULTS,
123	          },
124	        ];
125	      }
126	
127	      // Open the menu when the input value changes and the new value is not empty
128	      if (!isOpen) {
129	        setIsOpen(true);
130	      }
131	    }
132	
133	    setSelectOptions(newSelectOptions);
134	  }, [filterValue]);
135	
136	  const setActiveAndFocusedItem = (itemIndex: number) => {
137	    setFocusedItemIndex(itemIndex);
138	    const focusedItem = selectOptions[itemIndex];
139	    setActiveItemId(focusedItem.value);
140	  };
141	
142	  const resetActiveAndFocusedItem = () => {
143	    setFocusedItemIndex(null);
144	    setActiveItemId(null);
145	  };
146	
147	  const closeMenu = () => {
148	    setIsOpen(false);
149	    resetActiveAndFocusedItem();
150	  };
151	
152	  const onInputClick = () => {
153	    if (!isOpen) {
154	      setIsOpen(true);
155	    } else if (!inputValue) {
156	      closeMenu();
157	    }
158	  };
159	
160	  const selectOption = (selectedOption: string, content: string) => {
161	    setInputValue(String(content));
162	    setFilterValue('');
163	    setSelected(String(selectedOption));
164	    onChange?.(String(selectedOption));
165	    closeMenu();
166	  };
167	
168	  const onSelect = (
169	    _event: React.MouseEvent<Element, MouseEvent> | undefined,
170	    selectedValue: SelectOptionProps['value'] | undefined,
171	  ) => {
172	    if (
173	      selectedValue &&
174	      selectedValue !== NO_RESULTS &&
175	      typeof selectedValue === 'string' &&
176	      selectedValue !== selected
177	    ) {
178	      const optionText = selectOptions.find((option) => option.value === selectedValue)?.children;
179	      selectOption(selectedValue, optionText as string);
180	    }
181	  };
182	
183	  const onTextInputChange = (_event: React.FormEvent<HTMLInputElement>, typedValue: string) => {
184	    setInputValue(typedValue);
185	    setFilterValue(typedValue);
186	
187	    resetActiveAndFocusedItem();
188	
189	    if (typedValue !== selected) {
190	      setSelected('');
191	    }
192	  };
193	
194	  const handleMenuArrowKeys = (key: string) => {
195	    let indexToFocus = 0;
196	
197	    if (!isOpen) {
198	      setIsOpen(true);
199	    }
200	
201	    if (key === 'ArrowUp') {
202	      if (focusedItemIndex === null || focusedItemIndex === 0) {
203	        indexToFocus = selectOptions.length - 1;
204	      } else {
205	        indexToFocus = focusedItemIndex - 1;
206	      }
207	    }
208	
209	    if (key === 'ArrowDown') {
210	      // When no index is set or at the last index,
211	      // focus to the first, otherwise increment focus index
212	      if (focusedItemIndex === null || focusedItemIndex === selectOptions.length - 1) {
213	        indexToFocus = 0;
214	      } else {
215	        indexToFocus = focusedItemIndex + 1;
216	      }
217	    }
218	
219	    setActiveAndFocusedItem(indexToFocus);
220	  };
221	
222	  const onInputKeyDown = (event: React.KeyboardEvent<HTMLInputElement>) => {
223	    const focusedItem = focusedItemIndex !== null ? selectOptions[focusedItemIndex] : null;
224	
225	    switch (event.key) {
226	      case 'Enter':
227	        if (
228	          isOpen &&
229	          focusedItem &&
230	          focusedItem.value !== NO_RESULTS &&
231	          !focusedItem.isAriaDisabled
232	        ) {
233	          selectOption(focusedItem.value, focusedItem.children as string);
234	        }
235	
236	        if (!isOpen) {
237	          setIsOpen(true);
238	        }
239	
240	        break;
241	      case 'ArrowUp':
242	      case 'ArrowDown':
243	        event.preventDefault();
244	        handleMenuArrowKeys(event.key);
245	        break;
246	    }
247	  };
248	
249	  const onToggleClick = () => {
250	    setIsOpen(!isOpen);
251	    textInputRef?.current?.focus();
252	  };
253	
254	  const onClearButtonClick = () => {
255	    setSelected('');
256	    setInputValue('');
257	    setFilterValue('');
258	    resetActiveAndFocusedItem();
259	    textInputRef?.current?.focus();
260	    onChange?.('');
261	  };
262	
263	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => (
264	    <MenuToggle
265	      ref={toggleRef}
266	      variant="typeahead"
267	      aria-label="Select timezone"
268	      onClick={onToggleClick}
269	      isExpanded={isOpen}
270	      isDisabled={isDisabled}
271	    >
272	      <TextInputGroup isPlain>
273	        <TextInputGroupMain
274	          value={inputValue}
275	          onClick={onInputClick}
276	          onChange={onTextInputChange}
277	          onKeyDown={onInputKeyDown}
278	          id="timezone-typeahead-select-input"
279	          autoComplete="off"
280	          innerRef={textInputRef}
281	          placeholder={t('Select timezone')}
282	          {...(activeItemId && { 'aria-activedescendant': activeItemId })}
283	          role="combobox"
284	          isExpanded={isOpen}
285	          aria-controls="timezone-select-typeahead-listbox"
286	        />
287	
288	        <TextInputGroupUtilities {...(!inputValue ? { style: { display: 'none' } } : {})}>
289	          <Button variant="plain" onClick={onClearButtonClick} aria-label={t('Clear input value')} icon={<TimesIcon aria-hidden />} />
290	        </TextInputGroupUtilities>
291	      </TextInputGroup>
292	    </MenuToggle>
293	  );
294	
295	  return (
296	    <Select
297	      id="timezone-typeahead-select"
298	      isOpen={isOpen}
299	      selected={selected}
300	      onSelect={onSelect}
301	      onOpenChange={(isOpenValue) => {
302	        !isOpenValue && closeMenu();
303	      }}
304	      toggle={toggle}
305	      shouldFocusFirstItemOnOpen={false}
306	      popperProps={{ appendTo: 'inline' }}
307	      data-test={TestIds.TimezoneDropdown}
308	      isScrollable
309	    >
310	      {filterValue ? (
311	        <SelectGroup label={t('All Timezones')}>
312	          <SelectList>
313	            {selectOptions.map((option, index) => (
314	              <SelectOption
315	                key={option.value || option.children}
316	                isFocused={focusedItemIndex === index}
317	                className={option.className}
318	                id={option.value as string}
319	                {...option}
320	                ref={null}
321	              />
322	            ))}
323	          </SelectList>
324	        </SelectGroup>
325	      ) : (
326	        <>
327	          <SelectGroup label={t('Common Timezones')}>
328	            <SelectList>
329	              {commonTimezoneOptions.map((option, index) => (
330	                <SelectOption
331	                  key={option.value || option.children}
332	                  isFocused={focusedItemIndex === index}
333	                  id={option.value as string}
334	                  {...option}
335	                  ref={null}
336	                />
337	              ))}
338	            </SelectList>
339	          </SelectGroup>
340	          <SelectGroup label={t('All Timezones')}>
341	            <SelectList id="timezone-select-typeahead-listbox">
342	              {selectOptions.map((option, index) => (
343	                <SelectOption
344	                  key={option.value || option.children}
345	                  isFocused={focusedItemIndex === index}
346	                  id={option.value as string}
347	                  {...option}
348	                  ref={null}
349	                />
350	              ))}
351	            </SelectList>
352	          </SelectGroup>
353	        </>
354	      )}
355	    </Select>
356	  );
357	};

